const google = $('Scraper avis Google Places').item.json.result || {};
const googleReviews = (google.reviews || []).slice(0, 10);
const noteGoogle = google.rating || 0;
const nbAvisGoogle = google.user_ratings_total || 0;

const trustpilot = $('Récupérer avis Trustpilot').item.json || {};
const noteTrustpilot = trustpilot.score?.trustScore || 0;
const nbAvisTrustpilot = trustpilot.numberOfReviews?.total || 0;

const tousLesAvis = [
  ...googleReviews.map(r => ({ source: 'Google', auteur: r.author_name, note: r.rating, texte: r.text, date: new Date(r.time * 1000).toISOString() })),
];

const noteGlobale = (noteGoogle * nbAvisGoogle + noteTrustpilot * nbAvisTrustpilot) / Math.max(nbAvisGoogle + nbAvisTrustpilot, 1);

return {
  note_google: noteGoogle,
  nb_avis_google: nbAvisGoogle,
  note_trustpilot: noteTrustpilot,
  nb_avis_trustpilot: nbAvisTrustpilot,
  note_globale: Math.round(noteGlobale * 10) / 10,
  total_avis: nbAvisGoogle + nbAvisTrustpilot,
  avis_recents: tousLesAvis,
  periode_analyse: new Date().toLocaleDateString('fr-FR')
};

const content = $input.item.json.message.content;
let analyse;
try {
  const match = content.match(/\{[\s\S]*\}/);
  analyse = JSON.parse(match[0]);
} catch(e) { analyse = { sentiment_global: 'neutre', resume_executif: content }; }
return { ...analyse, data: $('Consolider avis').item.json };

